import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin-dashboard.css';
import '../../styles/admin-layout.css';
import DashboardCard from '../../components/DashboardCard';
import '../../styles/dashboard-cards.css';

export const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchUsers();
    fetchRecentLogins();
  }, []);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await adminService.getAllUsers();
      setUsers(response.data.data || []);
    } catch (err) {
      setError('Lỗi tải danh sách người dùng');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const [recentLogins, setRecentLogins] = useState([]);

  const fetchRecentLogins = async () => {
    try {
      const resp = await adminService.getActivityLogs({ action: 'LOGIN', limit: 6 });
      setRecentLogins(resp.data.data || []);
    } catch (err) {
      console.error('Lỗi tải lịch sử đăng nhập gần đây', err);
    }
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleString('vi-VN', {
      year: 'numeric', month: '2-digit', day: '2-digit',
      hour: '2-digit', minute: '2-digit'
    });
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center admin-dashboard__loading-container">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }
  return (
    <div className="dashboard admin-page">

      {error && <div className="alert alert-error">{error}</div>}

      <div className="admin-dashboard-hero">
        <div>
          <h1 className="admin-dashboard-hero__title">Bảng điều khiển quản trị</h1>
          <p className="admin-dashboard-hero__subtitle">Giao diện quản lý — tập trung vào người dùng và bảo mật</p>
        </div>
        <div className="quick-actions">
          <a className="btn btn-primary" href="/admin/users">Quản lý người dùng</a>
          <a className="btn btn-secondary" href="/admin/user-login-history">Lịch sử đăng nhập</a>
        </div>
      </div>

      <div className="dashboard-cards-container">
        <DashboardCard title="Tổng người dùng" value={users.length} description="Số lượng tài khoản hiện có" />
      </div>

      <div className="grid-2" style={{ alignItems: 'start' }}>
        <div className="card">
          <h3>Người dùng đăng nhập gần đây</h3>
          {recentLogins.length > 0 ? (
            <ul className="recent-logins-list">
              {recentLogins.map((log) => (
                <li key={`login-${log.audit_id}`}>
                  <div>
                    <div style={{ fontWeight: 600 }}>{log.actor_full_name || log.actor_username || `#${log.user_id}`}</div>
                    <div className="meta">{log.actor_username || '-'}</div>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: '0.95rem' }}>{formatDate(log.logged_at)}</div>
                    <div className="meta">{log.entity_label || log.entity_type}</div>
                  </div>
                </li>
              ))}
            </ul>
          ) : (
            <p>Chưa có hoạt động đăng nhập gần đây.</p>
          )}
        </div>

        <div className="card">
          <h3>Hành động nhanh</h3>
          <div className="btn-group">
            <a className="btn btn-primary" href="/admin/users">Quản lý người dùng</a>
            <a className="btn btn-secondary" href="/admin/user-login-history">Xem lịch sử chi tiết</a>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
